package pages;import org.openqa.selenium.By;import org.openqa.selenium.WebDriver;public class CamareroPage {    private WebDriver driver;    public CamareroPage(WebDriver driver) {        this.driver = driver;    }    public boolean panelCamareroVisible() {        return driver.getPageSource().contains("camarero")                || driver.getPageSource().contains("Pre-Boleta");    }    public int cantidadBotonesPreBoleta() {        return driver.findElements(By.linkText("Pre-Boleta")).size();    }    public void abrirPreBoleta() {        driver.findElement(By.linkText("Pre-Boleta")).click();    }    public boolean detallePedidoVisible() {        return driver.getPageSource().contains("Detalle del Pedido");    }    public boolean totalesVisibles() {        return driver.getPageSource().contains("Total Importe")                && driver.getPageSource().contains("IGV")                && driver.getPageSource().contains("Total");    }    public boolean botonCompletarPagoVisible() {        return driver.findElements(By.xpath("//button[text()='Completar Pago']")).size() > 0;    }}